mapper.insert:
/* 템플릿 등록 */
INSERT  INTO TB_TMPLAT_INFO
      ( TMPLAT_ID
      , TMPLAT_NM
      , TMPLAT_SE_CODE
      , TMPLAT_COURS
      , USE_AT
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{tmplatId}
        , #{tmplatNm}
        , #{tmplatSeCode}
        , #{tmplatCours}
        , #{useAt}
        , #{frstRegisterId}
        , SYSDATE() )

mapper.select:
/* 템플릿 목록 조회 */ SELECT A.TMPLAT_ID , A.TMPLAT_NM , A.TMPLAT_SE_CODE , A.TMPLAT_COURS , A.USE_AT , A.FRST_REGISTER_ID , DATE_FORMAT(A.FRST_REGIST_PNTTM, '%Y-%m-%d') AS FRST_REGIST_PNTTM , B.USER_NM AS FRST_REGISTER_NM , C.CODE_NM AS TMPLAT_SE_CODE_NM FROM TB_TMPLAT_INFO A LEFT OUTER JOIN VW_USER_MASTER B ON A.FRST_REGISTER_ID = B.ESNTL_ID LEFT OUTER JOIN TB_CMMN_DETAIL_CODE C ON A.TMPLAT_SE_CODE = C.CODE WHERE C.CODE_ID = 'COM005'
AND A.TMPLAT_SE_CODE = #{tmplatSeCode}
AND A.TMPLAT_NM LIKE CONCAT('%', #{searchWrd}, '%')
AND C.CODE_NM LIKE CONCAT('%', #{searchWrd}, '%')
ORDER BY A.FRST_REGIST_PNTTM DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

/* 템플릿 목록 총 건수 조회 */ SELECT COUNT(A.TMPLAT_ID) FROM TB_TMPLAT_INFO A LEFT OUTER JOIN VW_USER_MASTER B ON A.FRST_REGISTER_ID = B.ESNTL_ID LEFT OUTER JOIN TB_CMMN_DETAIL_CODE C ON A.TMPLAT_SE_CODE = C.CODE WHERE C.CODE_ID = 'COM005'
AND A.TMPLAT_SE_CODE = #{tmplatSeCode}
AND A.TMPLAT_NM LIKE CONCAT('%', #{searchWrd}, '%')
AND C.CODE_NM LIKE CONCAT('%', #{searchWrd}, '%')

mapper.update:
/* 템플릿 수정 */
UPDATE  TB_TMPLAT_INFO
   SET  TMPLAT_SE_CODE  = #{tmplatSeCode}
      , TMPLAT_COURS    = #{tmplatCours}
      , USE_AT          = #{useAt}
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = SYSDATE()
 WHERE  TMPLAT_ID = #{tmplatId}

/* 템플릿 논리 삭제 */
UPDATE  TB_TMPLAT_INFO
   SET  USE_AT          = 'N'
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = SYSDATE()
 WHERE  TMPLAT_ID = #{tmplatId}
